436	/** Обычный тест: N× single_choice, ровно 4 варианта (N по запросу, по умолчанию 10) */
437	export function parseAndValidateRegularQuestions(questions: unknown, expectedCount = 10): IQuestion[] {
438	  if (!Array.isArray(questions)) {
439	    throw new Error('OpenAI response: поле questions отсутствует или не массив.');
440	  }
441	  if (questions.length !== expectedCount) {
442	    throw new Error(
443	      `Обычный тест: ожидалось ровно ${expectedCount} вопросов, получено ${questions.length}.`
444	    );
445	  }
446	  return questions.map((raw, index) => validateRegularQuestion(raw, index));
447	}
