449	/**
450	 * Best-effort валидация набора single_choice вопросов (для банка): валидные оставляем,
451	 * невалидные молча отбрасываем. Бросает только если не уцелел ни один вопрос.
452	 */
453	export function parseRegularQuestionsLenient(questions: unknown): IQuestion[] {
454	  if (!Array.isArray(questions)) {
455	    throw new Error('OpenAI response: поле questions отсутствует или не массив.');
456	  }
457	  const valid: IQuestion[] = [];
458	  questions.forEach((raw, index) => {
459	    try {
460	      const q = validateRegularQuestion(raw, index);
461	      // Качество банка: 4 варианта должны быть различны (иначе вопрос неполноценный).
462	      const opts = (q.options ?? []).map((o) => o.trim().toLowerCase());
463	      if (new Set(opts).size !== opts.length) {
464	        throw new Error(`Вопрос ${index + 1}: варианты ответа не уникальны`);
465	      }
466	      valid.push(q);
467	    } catch (e) {
468	      console.warn('[bank] вопрос отброшен при валидации:', (e as Error).message);
469	    }
470	  });
471	  if (valid.length === 0) {
472	    throw new Error('Ни один вопрос не прошёл валидацию (все отброшены).');
473	  }
474	  return valid;
475	}

